import React from 'react'
import styled from 'styled-components'
import Header from '../components/Header'
import Navbar from '../components/Navbar'

const SellWrapper = styled.div `
display:flex;
flex-direction:column;
align-items:flex-start;
width:55%;
margin:70px auto;
`

const Head = styled.div ``

const BodySection = styled.div `
margin:40px 0;
`

const PhotoUploadSection = styled.div ``

const Title = styled.div `
font-size:1.8rem;
font-weight:900;
`

const SectionBlockTitle = styled.div `
font-size:1.5rem;
font-weight:800;
letter-spacing:2px;
color:rgba(0,0,0,0.7);
`

const Details = styled.div `
`

const GridWrapper =  styled.div `
display:grid;
grid-template-columns: auto auto;
grid-template-rows: auto auto;
grid-gap:60px 60px;
width:100%;
margin:30px 0;
`

const Department = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Categories = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Designer = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`

const Size = styled.select `
width:360px;
height:40px;
border:1px solid grey;
color:grey;
border-radius:6px;
`
const Option = styled.option ``


const ItemName = styled.div ``

const Color = styled.div ``

const Condition = styled.div ``

const Description = styled.div ``

const Price = styled.div ``

const Photo = styled.div ``

export default function Sell () {
	return (
		<>
			<Header />
			<Navbar />
			<SellWrapper>
				<Head>
					<Title>Add a New Listing</Title>
				</Head>
				<BodySection>
					<Details>
						<SectionBlockTitle>Details</SectionBlockTitle>
						<GridWrapper>
							<Department value='Department'>
								<Option>Please Select Your Department</Option>
								<Option>MensWear</Option>
								<Option>WomensWear</Option>
							</Department>
							<Categories>
								<Option>Please Select Your Category</Option>
								<Option>MensWear</Option>
								<Option>WomensWear</Option>
							</Categories>
							<Designer>
								<Option>Please Select Your Degigner</Option>
								<Option>Maison Margiela</Option>
								<Option>Louis Vuitton</Option>
							</Designer>
							<Size></Size>
						</GridWrapper>
					</Details>
					<ItemName>
						<SectionBlockTitle>Item Name</SectionBlockTitle>
					</ItemName>
					<Color>
						<SectionBlockTitle>Color</SectionBlockTitle>
					</Color>
					<Condition>
						<SectionBlockTitle>Condition</SectionBlockTitle>
					</Condition>
					<Description>
						<SectionBlockTitle>Description</SectionBlockTitle>
					</Description>
					<Price>
						<SectionBlockTitle>Price</SectionBlockTitle>
					</Price>
				</BodySection>
				<PhotoUploadSection>
					<Photo></Photo>
				</PhotoUploadSection>
			</SellWrapper>

		</>
	)
}
